fn solve(landStartTime: Vec<i64>, landDuration: Vec<i64>, waterStartTime: Vec<i64>, waterDuration: Vec<i64>) -> i64 {
    let mut min_time = i64::MAX;

    for i in 0..landStartTime.len() {
        for j in 0..waterStartTime.len() {
            // Land first, then water
            let land_end = std::cmp::max(landStartTime[i], landStartTime[i] + landDuration[i]);
            let water_start = std::cmp::max(waterStartTime[j], land_end);
            let water_end = water_start + waterDuration[j];
            min_time = std::cmp::min(min_time, water_end);

            // Water first, then land
            let water_end = std::cmp::max(waterStartTime[j], waterStartTime[j] + waterDuration[j]);
            let land_start = std::cmp::max(landStartTime[i], water_end);
            let land_end = land_start + landDuration[i];
            min_time = std::cmp::min(min_time, land_end);
        }
    }

    min_time
}
